            aOrbiterI = RotL64((aOrbiterI * 4902851645143648719U), 29U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 4134054599271436628U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterE) ^ 8888708066244229144U) ^ aNonceWordP;
            aOrbiterD = RotL64((aOrbiterD * 10840436340976388967U), 11U);
