            aWandererB = aWandererB + (((RotL64(aScatter, 47U) + aOrbiterK) + RotL64(aOrbiterH, 48U)) + aPhaseGWandererUpdateSaltA[(((31U - aIndex) + 7U)) & S_SALT1]);
